export class NewsPage{constructor(){this.data=[],this.init()}async init(){this.data=[{id:1,date:"10.03.2026",messages:[{time:"04:00",text:"А почему Магистр Йода не пошёл в аспирантуру?",important:!0},{time:"17:00",text:"Денег нет, но вы держитесь",important:!1}]},{id:2,date:"16.03.2026",messages:[{time:"13:37",text:"Ни что так не губит как к 11 туз",important:!1}]},{id:3,date:"05.04.2026",messages:[{time:"8:00",text:"14.04.26 - Собрание в 118 кабинете в 8:00",important:!0}]},{id:4,date:"24.04.2026",messages:[{time:"12:00",text:"В валик пойдёте?",important:!1}]}],this.showNews()}showNews(){const t=document.getElementById("news-items");this.data.forEach(e=>{const s=document.createElement("div");s.classList.add("item");const a=document.createElement("div");a.classList.add("date"),a.innerText=e.date;const d=document.createElement("div");d.classList.add("messages"),e.messages.forEach(t=>{const e=document.createElement("div");e.classList.add("message");const s=document.createElement("div");s.classList.add("important-circle"),s.innerText="!";const a=document.createElement("div");a.classList.add("time"),a.innerText=t.time+":";const i=document.createElement("div");i.classList.add("text"),i.innerText=t.text,!0===t.important&&e.classList.add("important"),e.appendChild(a),e.appendChild(i),e.appendChild(s),d.append(e)}),s.appendChild(a),s.appendChild(d),t.appendChild(s)})}}